-- Create "notification_channel_profiles" table
CREATE TABLE "notification_channel_profiles" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "name" character varying NOT NULL,
  "kind" character varying NOT NULL DEFAULT 'webhook',
  "secret_ref" character varying NOT NULL,
  "delivery_scopes" jsonb NOT NULL,
  "enabled" boolean NOT NULL DEFAULT false,
  "labels" jsonb NOT NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "notification_channel_profiles_name_key" to table: "notification_channel_profiles"
CREATE UNIQUE INDEX "notification_channel_profiles_name_key" ON "notification_channel_profiles" ("name");
-- Create index "notificationchannelprofile_delivery_scopes" to table: "notification_channel_profiles"
CREATE INDEX "notificationchannelprofile_delivery_scopes" ON "notification_channel_profiles" USING GIN ("delivery_scopes");
-- Create index "notificationchannelprofile_kind_enabled" to table: "notification_channel_profiles"
CREATE INDEX "notificationchannelprofile_kind_enabled" ON "notification_channel_profiles" ("kind", "enabled");
-- Create index "notificationchannelprofile_labels" to table: "notification_channel_profiles"
CREATE INDEX "notificationchannelprofile_labels" ON "notification_channel_profiles" USING GIN ("labels");
